// Janela: últimas 48h para pegar tweets dos últimos 2 dias
const now = new Date();
const cutoff = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();
const today = now.toISOString().split('T')[0];
return [{ json: { cutoff, today, now: now.toISOString() } }];

// Twitter v2 permite até 100 IDs por chamada
const tweets = Array.isArray($input.first().json) ? $input.first().json : [$input.first().json];
const ids = tweets.map(t => t.tweet_id).join(',');
return [{ json: { ids, tweets, count: tweets.length } }];

// Pegar tweets originais (com format/slot) e métricas do Twitter
const metricsResponse = $input.first().json;
const tweetsData = $('Build Tweet IDs').first().json.tweets;

const metrics = metricsResponse.data || [];
const now = new Date().toISOString();

// Função de score: 0-100
function scorePerformance(m) {
  const imp = m.impression_count || 0;
  const likes = m.like_count || 0;
  const rt = m.retweet_count || 0;
  const rep = m.reply_count || 0;
  const bk = m.bookmark_count || 0;

  // Pesos: engajamento real vale mais que impressões
  const eng = likes * 3 + rt * 5 + rep * 4 + bk * 4;

  // Score baseado em benchmarks para conta nova/crescendo
  // Viral: >1000 impressões + >20 likes OU eng > 100
  // Good: >300 impressões + >5 likes
  // Normal: >50 impressões
  // Flop: resto
  let score = 0;
  if (imp > 0) score += Math.min(30, Math.floor(imp / 50)); // até 30 pts por impressões
  if (likes > 0) score += Math.min(30, likes * 3);           // até 30 pts por likes
  if (rt > 0) score += Math.min(20, rt * 5);                 // até 20 pts por RT
  if (rep > 0) score += Math.min(10, rep * 2);               // até 10 pts por replies
  if (bk > 0) score += Math.min(10, bk * 2);                 // até 10 pts por bookmarks
  score = Math.min(100, score);

  let label;
  if (score >= 70) label = 'viral';
  else if (score >= 40) label = 'good';
  else if (score >= 15) label = 'normal';
  else label = 'flop';

  return { score, label, imp, likes, rt, rep, bk };
}

// Mapear métricas para tweets originais
const results = metrics.map(m => {
  const original = tweetsData.find(t => t.tweet_id === m.id) || {};
  const pm = m.public_metrics || {};
  const s = scorePerformance(pm);
  return {
    tweet_id: m.id,
    tweet_text: original.tweet_text,
    format: original.format,
    scheduled_slot: original.scheduled_slot,
    posted_at: original.posted_at,
    impressions: s.imp,
    likes: s.likes,
    retweets: s.rt,
    replies: s.rep,
    bookmarks: s.bk,
    performance_score: s.score,
    performance_label: s.label,
    checked_at: now
  };
});

// Highlights para notificar
const virais = results.filter(r => r.performance_label === 'viral');
const bons = results.filter(r => r.performance_label === 'good');

return [{ json: { results, virais, bons, total: results.length, now } }];

// Atualizar cada tweet via Supabase REST API
const { results } = $input.first().json;
const supabaseUrl = $vars.SUPABASE_URL;
const supabaseKey = $vars.SUPABASE_KEY;

const updates = results.map(r => ({
  url: `${supabaseUrl}/rest/v1/tw_posted?tweet_id=eq.${r.tweet_id}`,
  method: 'PATCH',
  headers: {
    'apikey': supabaseKey,
    'Authorization': `Bearer ${supabaseKey}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: JSON.stringify({
    impressions: r.impressions,
    likes: r.likes,
    retweets: r.retweets,
    replies: r.replies,
    bookmarks: r.bookmarks,
    performance_score: r.performance_score,
    performance_label: r.performance_label,
    checked_at: r.checked_at
  })
}));

// Em n8n não temos fetch nativo — retornar para nó HTTP em batch
// Passamos o primeiro update + lista completa para processamento sequencial
return [{ json: { updates, results: $input.first().json.results, virais: $input.first().json.virais, bons: $input.first().json.bons, total: $input.first().json.total } }];

const { results, virais, bons, total } = $('Score & Prepare Updates').first().json;

// Emojis por label
const labelEmoji = { viral: '🔥', good: '✅', normal: '📊', flop: '💤' };

// Tabela de resultados
const linhas = results
  .sort((a, b) => b.performance_score - a.performance_score)
  .map(r => {
    const emoji = labelEmoji[r.performance_label] || '📊';
    const slot = r.scheduled_slot || '?';
    const fmt = r.format ? r.format.replace('_', ' ') : '?';
    return `${emoji} [${slot}] ${fmt}\n   👁 ${r.impressions} imp • ❤️ ${r.likes} • 🔁 ${r.retweets} • 💬 ${r.replies}\n   Score: ${r.performance_score}/100 — ${r.performance_label}\n   🔗 https://x.com/bodybasehealth/status/${r.tweet_id}`;
  })
  .join('\n\n');

// Destaques
let destaques = '';
if (virais.length > 0) {
  destaques += `\n🔥 VIRAIS: ${virais.length} tweet${virais.length > 1 ? 's' : ''}`;
}
if (bons.length > 0) {
  destaques += `\n✅ BONS: ${bons.length} tweet${bons.length > 1 ? 's' : ''}`;
}

// Insight de aprendizado
const topFormat = results
  .filter(r => r.format)
  .sort((a, b) => b.performance_score - a.performance_score)[0];
const insight = topFormat
  ? `\n💡 Melhor formato hoje: ${topFormat.format} (score ${topFormat.performance_score})`
  : '';

const report = `📊 PERFORMANCE DIÁRIA — @bodybasehealth\n${'─'.repeat(35)}\nAnalisados: ${total} tweet${total > 1 ? 's' : ''}${destaques}${insight}\n\n${linhas}`;

return [{ json: { report, hasHighlights: virais.length > 0 || bons.length > 0, virais, bons } }];
